import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import useIsMobile from '../hooks/useIsMobile';
import LoadingState from '../components/LoadingState';
import ExportBar from '../components/ExportBar';
import usePageTitle from '../hooks/usePageTitle';
import s from './NewsFeedPage.module.css';

// ── Sentiment ──────────────────────────────────────────────────────────────

const BULLISH_KEYWORDS = [
  'beats', 'beat', 'upgrade', 'upgraded', 'surge', 'surges', 'surged',
  'rally', 'rallies', 'rallied', 'record', 'high', 'profit', 'profits',
  'growth', 'gain', 'gains', 'bullish', 'positive', 'buy', 'outperform',
  'strong', 'raises', 'raised', 'exceeds', 'exceeded', 'boost', 'boosted',
];
const BEARISH_KEYWORDS = [
  'miss', 'misses', 'missed', 'downgrade', 'downgraded', 'crash', 'crashes',
  'crashed', 'fall', 'falls', 'fell', 'drop', 'drops', 'dropped', 'loss',
  'losses', 'bearish', 'negative', 'sell', 'underperform', 'weak', 'weak',
  'cuts', 'cut', 'slump', 'slumps', 'slumped', 'decline', 'declines',
  'declined', 'warn', 'warns', 'warned', 'warning', 'fear', 'fears',
];

function inferSentiment(text) {
  if (!text) return 'neutral';
  const lower = text.toLowerCase();
  const words = lower.split(/\W+/);
  let score = 0;
  for (const w of words) {
    if (BULLISH_KEYWORDS.includes(w)) score += 1;
    if (BEARISH_KEYWORDS.includes(w)) score -= 1;
  }
  if (score > 0) return 'bullish';
  if (score < 0) return 'bearish';
  return 'neutral';
}

function sentimentConfig(sentiment, headline) {
  const resolved = sentiment && sentiment !== 'neutral'
    ? sentiment
    : inferSentiment(headline);
  switch ((resolved || '').toLowerCase()) {
    case 'bullish': case 'positive':
      return { color: 'var(--color-green, #22C55E)', bg: 'rgba(63,185,80,0.12)', label: 'Bullish' };
    case 'bearish': case 'negative':
      return { color: 'var(--color-red, #EF4444)', bg: 'rgba(248,81,73,0.12)', label: 'Bearish' };
    default:
      return { color: 'var(--color-text-secondary, #90A3AF)', bg: 'rgba(139,148,158,0.12)', label: 'Neutral' };
  }
}

// ── Ticker extraction ──────────────────────────────────────────────────────

// Common English words to exclude from ticker matching
const STOP_WORDS = new Set([
  'A', 'I', 'THE', 'AND', 'OR', 'FOR', 'IN', 'AT', 'TO', 'ON', 'BY', 'OF',
  'IT', 'IS', 'AS', 'BE', 'WE', 'US', 'AN', 'SO', 'IF', 'UP', 'DO', 'NO',
  'GO', 'MY', 'HE', 'SHE', 'NEW', 'NOT', 'ALL', 'ARE', 'HAS', 'HAD', 'WAS',
  'ITS', 'CAN', 'MAY', 'DID', 'BUT', 'HOW', 'WHO', 'PRE', 'END', 'WILL',
  'FROM', 'INTO', 'OVER', 'THAT', 'WITH', 'THIS', 'THEY', 'HAVE', 'BEEN',
  'WERE', 'WHEN', 'YOUR', 'MORE', 'THAN', 'ALSO', 'WHAT', 'JUST', 'SAYS',
  'SAID', 'YEAR', 'NEXT', 'LAST', 'AMID', 'SETS', 'HITS', 'SEES', 'GETS',
  'BUYS', 'SELL', 'RISE', 'FELL', 'DEAL', 'PLAN', 'MOVE', 'SHOW', 'TAKE',
  'MAKE', 'OPEN', 'CALL', 'DOWN', 'HIGH', 'RISK', 'RATE', 'FUND', 'DATA',
  'FIRM', 'UNIT', 'CORP', 'INC', 'ETF', 'CEO', 'CFO', 'COO', 'IPO', 'M&A',
  'SEC', 'FED', 'FDA', 'GDP', 'CPI', 'IMF', 'NYSE', 'NASDAQ', 'SPX', 'DOW',
  'BUY', 'USD', 'EUR', 'GBP', 'JPY', 'AUD', 'CAD', 'CHF', 'CNY', 'HKD',
]);

function extractTickers(text) {
  if (!text) return [];
  // Match 1-5 uppercase letters, optionally preceded by $ sign
  const matches = text.match(/\$?([A-Z]{1,5})\b/g) || [];
  const seen = new Set();
  const result = [];
  for (const m of matches) {
    const ticker = m.replace('$', '');
    if (!STOP_WORDS.has(ticker) && !seen.has(ticker) && ticker.length >= 2) {
      seen.add(ticker);
      result.push(ticker);
    }
  }
  return result;
}

// ── Source badge colors ────────────────────────────────────────────────────

const SOURCE_COLORS = {
  reuters:     { color: '#F59E0B', bg: 'rgba(245,158,11,0.12)' },
  bloomberg:   { color: '#60A5FA', bg: 'rgba(96,165,250,0.12)' },
  cnbc:        { color: '#EF4444', bg: 'rgba(239,68,68,0.12)' },
  sec:         { color: '#8B5CF6', bg: 'rgba(139,92,246,0.12)' },
  'wall street journal': { color: '#60A5FA', bg: 'rgba(96,165,250,0.12)' },
  wsj:         { color: '#60A5FA', bg: 'rgba(96,165,250,0.12)' },
  marketwatch: { color: '#22C55E', bg: 'rgba(34,197,94,0.12)' },
  'financial times': { color: '#F97316', bg: 'rgba(249,115,22,0.12)' },
  ft:          { color: '#F97316', bg: 'rgba(249,115,22,0.12)' },
  barrons:     { color: '#F59E0B', bg: 'rgba(245,158,11,0.12)' },
  "barron's":  { color: '#F59E0B', bg: 'rgba(245,158,11,0.12)' },
  benzinga:    { color: '#A78BFA', bg: 'rgba(167,139,250,0.12)' },
  seekingalpha:{ color: '#34D399', bg: 'rgba(52,211,153,0.12)' },
  zacks:       { color: '#60A5FA', bg: 'rgba(96,165,250,0.12)' },
  motleyfool:  { color: '#22C55E', bg: 'rgba(34,197,94,0.12)' },
  yahoo:       { color: '#A78BFA', bg: 'rgba(167,139,250,0.12)' },
  finnhub:     { color: '#34D399', bg: 'rgba(52,211,153,0.12)' },
};

function sourceStyle(source) {
  if (!source) return null;
  const key = source.toLowerCase().trim();
  for (const [k, v] of Object.entries(SOURCE_COLORS)) {
    if (key.includes(k)) return v;
  }
  return null;
}

// ── Utilities ──────────────────────────────────────────────────────────────

function stripUrls(text) {
  if (!text) return '';
  return text
    .replace(/https?:\/\/[^\s)>\]"']+/gi, '')
    .replace(/www\.[^\s)>\]"']+/gi, '')
    .replace(/[a-zA-Z0-9-]+\.(com|org|net|io|cc|co|ca|uk|au|de|fr|jp)\b[^\s)>\]"']*/gi, '')
    .replace(/\s{2,}/g, ' ')
    .replace(/[\s,.:;]+$/g, '')
    .trim();
}

function isUrl(text) {
  if (!text) return false;
  return /^https?:\/\//i.test(text.trim()) || /^www\./i.test(text.trim());
}

function cleanSourceName(source) {
  if (!source) return 'News';
  if (isUrl(source)) {
    try {
      const hostname = new URL(source.startsWith('www.') ? 'https://' + source : source).hostname;
      return hostname.replace(/^www\./, '').split('.')[0].charAt(0).toUpperCase() +
             hostname.replace(/^www\./, '').split('.')[0].slice(1);
    } catch { return 'News'; }
  }
  return source;
}

function timeAgo(ts) {
  if (!ts) return '';
  const secs = Math.floor(Date.now() / 1000 - (typeof ts === 'number' ? ts : new Date(ts).getTime() / 1000));
  if (secs < 60) return 'just now';
  if (secs < 3600) return `${Math.floor(secs / 60)}m ago`;
  if (secs < 86400) return `${Math.floor(secs / 3600)}h ago`;
  return `${Math.floor(secs / 86400)}d ago`;
}

// Merge tickers from API field + headline extraction
function getArticleTickers(item) {
  const apiTickers = [];
  if (item.related && !isUrl(item.related)) {
    // "related" can be comma-separated like "AAPL,MSFT" or a single ticker
    apiTickers.push(...item.related.split(',').map(s => s.trim().toUpperCase()).filter(Boolean));
  }
  if (item.symbols && item.symbols.length > 0) {
    apiTickers.push(...item.symbols.map(s => s.toUpperCase()));
  }
  const headline = item.headline || item.title || '';
  const extracted = extractTickers(headline);
  // Merge, dedup
  const seen = new Set(apiTickers);
  const merged = [...apiTickers];
  for (const t of extracted) {
    if (!seen.has(t)) {
      seen.add(t);
      merged.push(t);
    }
  }
  return merged.slice(0, 6);
}

// Check if article is relevant to portfolio positions
function isPortfolioRelevant(articleTickers, portfolioSymbols) {
  if (!portfolioSymbols || portfolioSymbols.size === 0) return false;
  return articleTickers.some(t => portfolioSymbols.has(t));
}

// ── Main Component ─────────────────────────────────────────────────────────

export default function NewsFeedPage() {
  usePageTitle('News Feed');
  const isMobile = useIsMobile();
  const navigate = useNavigate();

  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [source, setSource] = useState('');
  const [category, setCategory] = useState('general');
  const [symbolFilter, setSymbolFilter] = useState('');
  const [portfolioSymbols, setPortfolioSymbols] = useState(new Set());

  const hasLoaded = useRef(false);

  // Fetch open positions to build portfolio symbol set
  useEffect(() => {
    api('/positions').then(data => {
      if (!data) return;
      const positions = data.positions || data || [];
      const syms = new Set();
      for (const p of positions) {
        const sym = (p.symbol || p.ticker || '').toUpperCase();
        if (sym) syms.add(sym);
      }
      setPortfolioSymbols(syms);
    }).catch(() => {});
  }, []);

  const fetchNews = useCallback(async () => {
    if (!hasLoaded.current) setLoading(true);
    setError(null);
    try {
      const data = await api(`/news?category=${category}&limit=30`);
      if (!data) throw new Error('API unreachable');
      setArticles(data.articles || []);
      setSource(data.source || '');
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
    hasLoaded.current = true;
  }, [category]);

  useEffect(() => {
    hasLoaded.current = false;
    fetchNews();
    const id = setInterval(fetchNews, 300000);
    return () => clearInterval(id);
  }, [fetchNews]);

  // Apply symbol filter
  const filterUpper = symbolFilter.trim().toUpperCase();
  const filteredArticles = filterUpper
    ? articles.filter(item => {
        const tickers = getArticleTickers(item);
        return tickers.some(t => t.includes(filterUpper));
      })
    : articles;

  function handleTickerClick(e, symbol) {
    e.preventDefault();
    e.stopPropagation();
    navigate(`/charts?symbol=${symbol}`);
  }

  // ── Mobile layout ──────────────────────────────────────────────────────

  if (isMobile) return (
    <LoadingState loading={loading} error={error} empty={false} type="cards" onRetry={fetchNews}>
      <div className="mobile-page">
        <div className="mobile-page-header">
          <h1>News Feed</h1>
          <p>{filteredArticles.length} articles{source ? ` via ${source}` : ''}</p>
        </div>

        {/* Category pills */}
        <div className={s.mobileCategoryBar}>
          {['general', 'forex', 'crypto', 'merger'].map(cat => (
            <button key={cat} onClick={() => setCategory(cat)}
              className={`${s.mobileCategoryBtn} ${category === cat ? s.mobileCategoryBtnActive : ''}`}
            >{cat}</button>
          ))}
        </div>

        {/* Symbol filter */}
        <div className={s.mobileFilterRow}>
          <input
            className={s.symbolFilterInput}
            type="text"
            placeholder="Filter by symbol…"
            value={symbolFilter}
            onChange={e => setSymbolFilter(e.target.value)}
            spellCheck={false}
            autoCapitalize="characters"
          />
          {symbolFilter && (
            <button className={s.filterClearBtn} onClick={() => setSymbolFilter('')}>✕</button>
          )}
        </div>

        {loading ? (
          <div className="mobile-empty">Loading news...</div>
        ) : filteredArticles.length === 0 ? (
          <div className="mobile-empty">No articles</div>
        ) : (
          filteredArticles.map((item, idx) => {
            const sc = sentimentConfig(item.sentiment, item.headline || item.title);
            const tickers = getArticleTickers(item);
            const portfolioHit = isPortfolioRelevant(tickers, portfolioSymbols);
            const srcStyle = sourceStyle(cleanSourceName(item.source));
            return (
              <a key={item.id || idx} href={item.url || '#'} target="_blank" rel="noopener noreferrer" className={s.cardLink}>
                <div className="mobile-card" style={{ borderLeft: `3px solid ${sc.color}` }}>
                  <div className={s.mobileCardMeta}>
                    <span className={s.mobileCardSource} style={srcStyle ? { color: srcStyle.color } : {}}>
                      {cleanSourceName(item.source)}
                    </span>
                    <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                      {portfolioHit && (
                        <span className={s.portfolioBadge}>Portfolio</span>
                      )}
                      <span className={s.mobileSentimentBadge} style={{ background: sc.bg, color: sc.color }}>{sc.label}</span>
                    </div>
                  </div>
                  {(item.image || item.urlToImage || item.imageUrl || item.thumbnail) && (
                    <img
                      src={item.image || item.urlToImage || item.imageUrl || item.thumbnail}
                      alt=""
                      loading="lazy"
                      className={s.mobileCardImage}
                      onError={e => { e.target.style.display = 'none'; }}
                    />
                  )}
                  <div className={s.mobileCardTitle}>
                    {item.headline || item.title || ''}
                  </div>
                  <div style={{ display: 'flex', gap: 6, alignItems: 'center', flexWrap: 'wrap', marginTop: 4 }}>
                    <span className={s.mobileCardTime}>{timeAgo(item.datetime)}</span>
                    {tickers.slice(0, 4).map(sym => (
                      <button
                        key={sym}
                        className={`${s.tickerChip} ${portfolioSymbols.has(sym) ? s.tickerChipPortfolio : ''}`}
                        onClick={e => handleTickerClick(e, sym)}
                      >${sym}</button>
                    ))}
                  </div>
                </div>
              </a>
            );
          })
        )}
      </div>
    </LoadingState>
  );

  // ── Desktop layout ─────────────────────────────────────────────────────

  return (
    <LoadingState loading={loading} error={error} empty={false} type="cards" onRetry={fetchNews}>
      <div className={s.page}>
        {/* Header */}
        <div className={s.header}>
          <div>
            <h1 className={s.title}>News Feed</h1>
            <p className={s.subtitle}>
              Live market news and sentiment
              {source && <span className={s.sourceTag}>via {source}</span>}
            </p>
          </div>
          <div className={s.headerRight}>
            <div className={s.categoryBar}>
              {['general', 'forex', 'crypto', 'merger'].map(cat => (
                <button
                  key={cat}
                  onClick={() => setCategory(cat)}
                  className={`${s.categoryBtn} ${category === cat ? s.categoryBtnActive : ''}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Symbol filter row */}
        <div className={s.filterRow}>
          <div className={s.filterInputWrap}>
            <span className={s.filterIcon}>⌕</span>
            <input
              className={s.symbolFilterInput}
              type="text"
              placeholder="Filter by ticker symbol (e.g. AAPL)"
              value={symbolFilter}
              onChange={e => setSymbolFilter(e.target.value)}
              spellCheck={false}
              autoCapitalize="characters"
            />
            {symbolFilter && (
              <button className={s.filterClearBtn} onClick={() => setSymbolFilter('')}>✕</button>
            )}
          </div>
          {portfolioSymbols.size > 0 && (
            <span className={s.portfolioHint}>
              {portfolioSymbols.size} open position{portfolioSymbols.size !== 1 ? 's' : ''} tracked
            </span>
          )}
          {symbolFilter && (
            <span className={s.filterCount}>{filteredArticles.length} result{filteredArticles.length !== 1 ? 's' : ''}</span>
          )}
        </div>

        {filteredArticles.length === 0 && !error && (
          <div className={s.emptyState}>
            <div className={s.emptyTitle}>
              {symbolFilter ? `No news found for "${filterUpper}"` : 'No news articles available'}
            </div>
            <div className={s.emptySub}>
              {symbolFilter ? 'Try a different symbol or clear the filter' : 'Try a different category or check back later'}
            </div>
          </div>
        )}

        {/* Export bar */}
        <ExportBar data={filteredArticles} filename="news-feed-export" columns={['source', 'datetime', 'related', 'sentiment', 'headline', 'summary']} />

        {/* News cards */}
        <div className={s.cardList}>
          {filteredArticles.map((item, idx) => {
            const sc = sentimentConfig(item.sentiment, item.headline || item.title);
            const tickers = getArticleTickers(item);
            const portfolioHit = isPortfolioRelevant(tickers, portfolioSymbols);
            const srcName = cleanSourceName(item.source);
            const srcStyle = sourceStyle(srcName);
            return (
              <a
                key={item.id || idx}
                href={item.url || '#'}
                target="_blank"
                rel="noopener noreferrer"
                className={s.cardLink}
              >
                <div
                  className={`${s.card} ${portfolioHit ? s.cardPortfolio : ''}`}
                  style={{ borderLeft: `4px solid ${sc.color}` }}
                >
                  <div className={s.cardMeta}>
                    {/* Source badge */}
                    <span
                      className={s.cardSource}
                      style={srcStyle ? {
                        color: srcStyle.color,
                        background: srcStyle.bg,
                        border: `1px solid ${srcStyle.color}33`,
                      } : {}}
                    >
                      {srcName}
                    </span>

                    <span className={s.cardTime}>
                      {timeAgo(item.datetime)}
                    </span>

                    {/* Portfolio badge */}
                    {portfolioHit && (
                      <span className={s.portfolioBadge}>Portfolio</span>
                    )}

                    {/* Ticker chips (clickable) */}
                    {tickers.map(sym => (
                      <button
                        key={sym}
                        className={`${s.tickerChip} ${portfolioSymbols.has(sym) ? s.tickerChipPortfolio : ''}`}
                        onClick={e => handleTickerClick(e, sym)}
                        title={`View ${sym} chart`}
                      >${sym}</button>
                    ))}

                    {/* Sentiment badge */}
                    <span className={s.sentimentBadge} style={{ background: sc.bg, color: sc.color }}>
                      {sc.label}
                    </span>
                  </div>

                  <div className={s.cardBody}>
                    {(item.image || item.urlToImage || item.imageUrl || item.thumbnail) && (
                      <img
                        src={item.image || item.urlToImage || item.imageUrl || item.thumbnail}
                        alt=""
                        loading="lazy"
                        className={s.cardImage}
                        onError={e => { e.target.style.display = 'none'; }}
                      />
                    )}
                    <div className={s.cardContent}>
                      <h3 className={s.cardHeadline}>
                        {item.headline || item.title || ''}
                      </h3>
                      {item.summary && stripUrls(item.summary) && (
                        <p className={s.cardSummary}>
                          {(() => { const clean = stripUrls(item.summary); return clean.length > 200 ? clean.slice(0, 200) + '...' : clean; })()}
                        </p>
                      )}
                    </div>
                  </div>
                </div>
              </a>
            );
          })}
        </div>
      </div>
    </LoadingState>
  );
}
